    assert_eq!(rabbit.opaque_faces, 54);
    assert_eq!(rabbit.vertices.len(), 216);
    assert_eq!(rabbit.indices.len(), 324);
    assert!(rabbit
        .vertices
        .iter()
        .any(|vertex| vertex.color == shade_color(RABBIT_BROWN, 1.0)));
}

